# coding: utf-8
import base64
import hashlib
import hmac
import random
import sys
import time
from urllib.parse import quote

import requests


class Signature(object):
    def __init__(
        self, app_id: str, user_id: str, secret_key: str, sgn_method: str = "sha1"
    ):
        self.app_id = app_id
        self.user_id = user_id
        self.secret_key = secret_key
        self.sgn_method = sgn_method

    def sign(self, sgn_body=""):
        sgn_type = "apisign"
        version = "2020"
        app_id = self.app_id
        user_id = self.user_id
        timestamp = str(int(time.time()))
        nonce = str(random.randint(0, sys.maxsize))
        sgn_method = self.sgn_method
        sgn_body = quote(sgn_body)
        str_to_sign = ".".join(
            [version, app_id, user_id, timestamp, nonce, sgn_method, sgn_body]
        ).encode()
        signature = hmac.new(
            self.secret_key.encode(), str_to_sign, getattr(hashlib, sgn_method)
        ).digest()
        signature = base64.b64encode(signature).decode()
        return {
            "rainbow_sgn_type": sgn_type,
            "rainbow_version": version,
            "rainbow_app_id": app_id,
            "rainbow_user_id": user_id,
            "rainbow_timestamp": timestamp,
            "rainbow_nonce": nonce,
            "rainbow_sgn_method": sgn_method,
            "rainbow_sgn_body": sgn_body,
            "rainbow_signature": signature,
        }

    def __call__(self, request: requests.PreparedRequest) -> requests.PreparedRequest:
        if not all([self.user_id, self.secret_key]):
            return request
        request.headers.update(self.sign())
        return request
